		CurrentMinPower:          0,
		ActualPower:              5,
		AllowInfrastructureRetry: false,
	}, testFloorFinder{5, 7, 9})

	assert.Equal(t, TryLoopActionStop, transition.Action)
	assert.Equal(t, "infrastructure_no_retry_route", transition.Reason)
}

