package git

import (
	"context"
	"os"
	"path/filepath"
	"strings"
	"time"
)

const ddxDirSegment = ".ddx"

// FindProjectRoot walks up from startDir to find the git repository root.
// It returns the top-level directory of the git working tree. If startDir
// is not inside a git repository, it returns startDir unchanged.
//
// This is analogous to `git rev-parse --show-toplevel` and ensures that
// ddx always operates from the repository root regardless of the caller's
// working directory. Without this, running `ddx` from a subdirectory that
// contains its own `.ddx/` folder would silently use the wrong workspace.
func FindProjectRoot(startDir string) string {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	cmd := Command(ctx, startDir, "rev-parse", "--show-toplevel")
	out, err := cmd.Output()
	if err != nil {
		// Not in a git repo — fall back to the original directory.
		return startDir
	}
	root := strings.TrimSpace(string(out))
	if root == "" {
		return startDir
	}
	if physical := physicalGitRoot(startDir); physical != "" && !samePath(physical, root) {
		return physical
	}
	return root
}

// physicalGitRoot walks upward on disk until it finds a .git directory or
// linked-worktree .git file. This intentionally bypasses git's configured
// worktree resolution so a corrupted local core.worktree cannot redirect ddx
// away from the checkout the operator actually invoked.
func physicalGitRoot(startDir string) string {
	current, err := filepath.Abs(startDir)
	if err != nil {
		return ""
	}
	for {
		if _, statErr := os.Stat(filepath.Join(current, ".git")); statErr == nil {
			return current
		}
		parent := filepath.Dir(current)
		if parent == current {
			return ""
		}
		current = parent
	}
}

func samePath(a, b string) bool {
	if a == "" || b == "" {
		return false
	}
	cleanA, err := filepath.Abs(a)
	if err != nil {
		cleanA = filepath.Clean(a)
	}
	cleanB, err := filepath.Abs(b)
	if err != nil {
		cleanB = filepath.Clean(b)
	}
	if resolvedA, err := filepath.EvalSymlinks(cleanA); err == nil {
		cleanA = resolvedA
	}
	if resolvedB, err := filepath.EvalSymlinks(cleanB); err == nil {
		cleanB = resolvedB
	}
	return cleanA == cleanB
}

// FindNearestDDxWorkspace walks up from startDir to find the nearest ancestor
// inside the current git repository that contains a .ddx workspace.
//
// When startDir is inside a linked git worktree (e.g. an execute-bead
// isolated worktree under .ddx/.execute-bead-wt-* or a worktrunk sibling
// like repo.feature-branch/), it resolves to the PRIMARY worktree's .ddx/
// first, not the linked worktree's own .ddx/. This is critical because:
//
//   - bead store mutations must land in the canonical project bead queue,
//     not in an isolated worktree's private snapshot that will be discarded
//   - the primary worktree is the operator's source of truth; linked
//     worktrees are ephemeral execution contexts
//
// If no in-tree .ddx/ exists, it falls back to the canonical project root so
// callers can still route project state through ddxroot.Path for convention-
// root projects.
//
// Returns an empty string only when startDir is not inside a git repository
// and no ancestor contains .ddx/.
func FindNearestDDxWorkspace(startDir string) string {
	abs, err := filepath.Abs(startDir)
	if err != nil {
		return ""
	}

	// If we're inside a linked worktree, prefer the primary worktree's .ddx/.
	if primary := primaryWorktreeRoot(abs); primary != "" && primary != FindProjectRoot(abs) {
		return primary
	}

	gitRoot := FindProjectRoot(abs)
	current := abs
	for {
		candidate := filepath.Join(current, ddxDirSegment)
		if info, statErr := os.Stat(candidate); statErr == nil && info.IsDir() {
			return current
		}
		if current == gitRoot {
			break
		}
		parent := filepath.Dir(current)
		if parent == current {
			break
		}
		current = parent
	}

	if IsRepository(abs) {
		return gitRoot
	}
	return ""
}

// IsRepository checks if the current directory is a git repository.
func IsRepository(path string) bool {
	if path == "" {
		path = "."
	}

	cleanPath := filepath.Clean(path)
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	cmd := Command(ctx, cleanPath, "rev-parse", "--git-dir")
	return cmd.Run() == nil
}

// primaryWorktreeRoot returns the primary (non-linked) worktree directory
// for a given path inside a git repository, or "" if the path is not inside
// a linked worktree (or if resolution fails).
//
// Detection: `git rev-parse --git-common-dir` returns the shared .git
// directory. If that differs from `git rev-parse --git-dir`, we're in a
// linked worktree. The primary worktree is the parent directory of the
// common .git dir (unless the shared dir is a bare repo).
func primaryWorktreeRoot(startDir string) string {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	gitDirCmd := Command(ctx, startDir, "rev-parse", "--path-format=absolute", "--git-dir")
	gitDirOut, err := gitDirCmd.Output()
	if err != nil {
		return ""
	}
	gitDir := strings.TrimSpace(string(gitDirOut))

	commonDirCmd := Command(ctx, startDir, "rev-parse", "--path-format=absolute", "--git-common-dir")
	commonDirOut, err := commonDirCmd.Output()
	if err != nil {
		return ""
	}
	commonDir := strings.TrimSpace(string(commonDirOut))

	if gitDir == commonDir {
		// Not a linked worktree.
		return ""
	}

	// Common dir is either a bare repo or the primary worktree's .git dir.
	// If it's a .git directory, the primary worktree is its parent.
	if filepath.Base(commonDir) == ".git" {
		return filepath.Dir(commonDir)
	}
	// Bare repo: no primary worktree. Caller falls back to walk-up.
	return ""
}

package git

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"strings"
	"sync"
)

// Command returns a prepared *exec.Cmd for a git invocation that honors
// cmd.Dir / -C <path> rather than whatever GIT_DIR / GIT_WORK_TREE / etc.
// were set in the parent environment.
//
// Why this wrapper exists (ddx-aa8a5fb3):
// Git's repository-discovery rules mean that if GIT_DIR is set in the
// process environment, git uses THAT repo and ignores both -C <path> and
// the process's working directory for repository selection. ddx commands
// invoked from a git hook (lefthook pre-commit, pre-push, etc.) inherit
// the hook's GIT_DIR / GIT_WORK_TREE / GIT_INDEX_FILE. Without stripping
// those, any exec.Command("git", ...) inside ddx mutates the hook's
// repository (the outer one), producing core.bare=true flips and stray
// core.worktree entries in .git/config.
//
// The wrapper strips exactly git's "local env vars" set (the vars git
// itself clears when spawning worktree subprocesses). This is the
// canonical set documented by `git rev-parse --local-env-vars`. It
// preserves everything else, including GIT_SSH_COMMAND, GIT_TRACE*,
// GIT_AUTHOR/COMMITTER_NAME/EMAIL, and custom debugging overrides.
//
// Dir must be an absolute or working-directory-relative path; it is set
// on the returned cmd so that when no GIT_* local vars are in the
// environment, git discovers the repo from Dir.
func Command(ctx context.Context, dir string, args ...string) *exec.Cmd {
	warnOnce.Do(maybeWarnGitDirLeaked)

	cmd := exec.CommandContext(ctx, "git", args...)
	if dir != "" {
		cmd.Dir = dir
	}
	cmd.Env = CleanEnv()
	return cmd
}

// CleanEnv returns os.Environ() with every git local-env-var removed.
// Exported so sibling packages (e.g. internal/agent) that spawn NON-git
// subprocesses inside a worktree can use the same scrub — those child
// processes often invoke git themselves and need the same protection.
func CleanEnv() []string {
	vars := localEnvVars()
	src := os.Environ()
	out := make([]string, 0, len(src))
	for _, kv := range src {
		eq := strings.IndexByte(kv, '=')
		if eq < 0 {
			out = append(out, kv)
			continue
		}
		if vars[kv[:eq]] {
			continue
		}
		out = append(out, kv)
	}
	return out
}

// localEnvVars returns the set of environment variable names that git
// treats as repository-local (i.e. scoped to the current git process's
// repository selection and cleared when git itself spawns subprocesses
// for other worktrees). Result is cached for process lifetime.
//
// We query `git rev-parse --local-env-vars` once at first use so we pick
// up any vars a newer git version adds. If that query fails (git not on
// PATH, or restricted environment), fall back to the documented set.
func localEnvVars() map[string]bool {
	localEnvVarsOnce.Do(func() {
		set := map[string]bool{}
		// Use exec.Command directly here to avoid recursion through
		// Command(). This runs with inherited env on purpose: even if
		// GIT_DIR is set, `git rev-parse --local-env-vars` is a static
		// list of variable NAMES (not their values), so inherited env
		// doesn't affect the output.
		out, err := exec.Command("git", "rev-parse", "--local-env-vars").Output()
		if err == nil {
			for _, name := range strings.Fields(string(out)) {
				if name != "" {
					set[name] = true
				}
			}
		}
		// Fallback / supplement: the canonical set from git's source
		// (environment.c local_repo_env[]). Kept inline so ddx remains
		// functional even if `git rev-parse` is unavailable.
		for _, name := range []string{
			"GIT_DIR",
			"GIT_WORK_TREE",
			"GIT_INDEX_FILE",
			"GIT_COMMON_DIR",
			"GIT_OBJECT_DIRECTORY",
			"GIT_ALTERNATE_OBJECT_DIRECTORIES",
			"GIT_PREFIX",
			"GIT_INTERNAL_GETTEXT_SH_SCHEME",
			"GIT_SHALLOW_FILE",
			"GIT_NO_REPLACE_OBJECTS",
			"GIT_REPLACE_REF_BASE",
			"GIT_CONFIG",
			"GIT_CONFIG_GLOBAL",
			"GIT_CONFIG_SYSTEM",
			"GIT_CONFIG_PARAMETERS",
			"GIT_CONFIG_COUNT",
			"GIT_INDEX_VERSION",
			"GIT_LITERAL_PATHSPECS",
			"GIT_GLOB_PATHSPECS",
			"GIT_NOGLOB_PATHSPECS",
			"GIT_ICASE_PATHSPECS",
			"GIT_QUARANTINE_PATH",
			"GIT_INTERNAL_NEW_OBJECT_HOOK",
			"GIT_IMPLICIT_WORK_TREE",
		} {
			set[name] = true
		}
		localEnvVarsCache = set
	})
	return localEnvVarsCache
}

var (
	localEnvVarsOnce  sync.Once
	localEnvVarsCache map[string]bool

	warnOnce sync.Once
)

// maybeWarnGitDirLeaked emits a one-time stderr diagnostic when the
// parent environment has GIT_DIR set. This is the canonical smoke signal
// for hook-inherited env contamination; surfacing it during normal runs
// helps catch upstream leaks we haven't yet wrapped.
func maybeWarnGitDirLeaked() {
	if v := os.Getenv("GIT_DIR"); v != "" {
		fmt.Fprintf(os.Stderr,
			"ddx git wrapper: stripped inherited GIT_DIR=%q (likely hook context). "+
				"This is diagnostic; operation proceeds against cmd.Dir instead.\n", v)
	}
}

// execute-bead worker (runner > pre-built service > fresh service).
func (r *DefaultBeadReviewer) dispatchReviewRun(ctx context.Context, runtime AgentRunRuntime) (*Result, error) {
	rcfg, _ := ddxconfig.LoadAndResolve(r.ProjectRoot, ddxconfig.CLIOverrides{})
	return dispatchViaResolvedConfig(ctx, r.ProjectRoot, r.Service, r.Runner, rcfg, runtime)
}

// gitShow runs `git show <rev>` with pathspec exclusions for execution-
// evidence noise so the review prompt's <diff> section stays bounded even
// when an old commit tracked a multi-thousand-line session log. See
// EvidenceReviewExcludePathspecs and ddx-39e27896 for the regression.
func (r *DefaultBeadReviewer) gitShow(rev string) (string, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
	defer cancel()
	args := append([]string{"show", rev, "--", "."}, EvidenceReviewExcludePathspecs()...)
	out, err := internalgit.Command(ctx, r.ProjectRoot, args...).Output()
	if err != nil {
		return "", err
	}
	return string(out), nil
}

func (r *DefaultBeadReviewer) gitDiff(baseRev, resultRev string) (string, error) {
	if strings.TrimSpace(baseRev) == "" || strings.TrimSpace(resultRev) == "" {
		return "", fmt.Errorf("base_rev and result_rev are required")
	}
	ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
	defer cancel()
	args := append([]string{"diff", baseRev, resultRev, "--", "."}, EvidenceReviewExcludePathspecs()...)
	out, err := internalgit.Command(ctx, r.ProjectRoot, args...).Output()
	if err != nil {
		return "", err
	}
	return string(out), nil
}

func resolveReviewBaseRev(projectRoot, resultRev string) string {
	if resultRev == "" {
		return ""
	}
	out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", resultRev+"^").Output()
	if err != nil {
		return ""
	}
	return strings.TrimSpace(string(out))
}
